#include <stdio.h>
#include <time.h>

void log_error(const char* message) {
    time_t t = time(NULL);
    struct tm* now = localtime(&t);
    printf("[%02d:%02d:%02d] %s\n", now->tm_hour, now->tm_min, now->tm_sec, message);
}